// ── Pull data from each previous HTTP node ──
const currency = $('Fetch Currency Rates').item.json;
const weather  = $('Fetch Weather (Lahore)').item.json;
const crypto   = $('Fetch Crypto Prices').item.json;

// ── Currency ──
const usdPkr = currency.rates?.PKR?.toFixed(2)  || 'N/A';
const usdEur = currency.rates?.EUR?.toFixed(4)  || 'N/A';
const usdGbp = currency.rates?.GBP?.toFixed(4)  || 'N/A';
const usdAed = currency.rates?.AED?.toFixed(4)  || 'N/A';

// ── Weather ──
const tempC       = weather.current_weather?.temperature   || 'N/A';
const windKph     = weather.current_weather?.windspeed      || 'N/A';
const weatherCode = weather.current_weather?.weathercode;

// Simple weather description from WMO code
function describeWeather(code) {
  if (code === 0)            return '☀️ Clear sky';
  if (code <= 3)             return '⛅ Partly cloudy';
  if (code <= 48)            return '🌫️ Foggy';
  if (code <= 67)            return '🌧️ Rainy';
  if (code <= 77)            return '❄️ Snowy';
  if (code <= 82)            return '🌦️ Showers';
  if (code <= 99)            return '⛈️ Thunderstorm';
  return '🌡️ Unknown';
}

const weatherDesc = describeWeather(weatherCode);

// ── Crypto ──
const btcPrice  = crypto.bitcoin?.usd?.toLocaleString()          || 'N/A';
const btcChange = crypto.bitcoin?.usd_24h_change?.toFixed(2)     || 'N/A';
const ethPrice  = crypto.ethereum?.usd?.toLocaleString()         || 'N/A';
const ethChange = crypto.ethereum?.usd_24h_change?.toFixed(2)    || 'N/A';
const solPrice  = crypto.solana?.usd?.toLocaleString()           || 'N/A';
const solChange = crypto.solana?.usd_24h_change?.toFixed(2)      || 'N/A';

// ── Helper: format 24h change with arrow ──
function fmt(change) {
  if (change === 'N/A') return 'N/A';
  const n = parseFloat(change);
  return n >= 0 ? `🟢 +${change}%` : `🔴 ${change}%`;
}

// ── Build the report ──
const today = new Date().toLocaleDateString('en-PK', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const report = `
<!DOCTYPE html>
<html>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; color: #1a1a1a;">

  <div style="background: #0f172a; color: white; padding: 24px; border-radius: 12px 12px 0 0;">
    <h1 style="margin:0; font-size: 22px;">📊 Weekly Business Briefing</h1>
    <p style="margin: 6px 0 0; opacity: 0.7; font-size: 14px;">${today}</p>
  </div>

  <div style="border: 1px solid #e2e8f0; border-top: none; border-radius: 0 0 12px 12px; overflow: hidden;">

    <!-- Currency -->
    <div style="padding: 20px; border-bottom: 1px solid #e2e8f0;">
      <h2 style="margin: 0 0 14px; font-size: 16px;">💱 Currency Rates <span style="font-weight:normal; color:#64748b; font-size:13px;">(Base: USD)</span></h2>
      <table style="width:100%; border-collapse: collapse; font-size: 15px;">
        <tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:8px 0; color:#64748b;">USD → PKR</td><td style="text-align:right; font-weight:600;">₨ ${usdPkr}</td></tr>
        <tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:8px 0; color:#64748b;">USD → EUR</td><td style="text-align:right; font-weight:600;">€ ${usdEur}</td></tr>
        <tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:8px 0; color:#64748b;">USD → GBP</td><td style="text-align:right; font-weight:600;">£ ${usdGbp}</td></tr>
        <tr><td style="padding:8px 0; color:#64748b;">USD → AED</td><td style="text-align:right; font-weight:600;">د.إ ${usdAed}</td></tr>
      </table>
    </div>

    <!-- Weather -->
    <div style="padding: 20px; border-bottom: 1px solid #e2e8f0; background: #f8fafc;">
      <h2 style="margin: 0 0 14px; font-size: 16px;">🌤️ Weather — Lahore, Pakistan</h2>
      <table style="width:100%; border-collapse: collapse; font-size: 15px;">
        <tr style="border-bottom:1px solid #e2e8f0;"><td style="padding:8px 0; color:#64748b;">Condition</td><td style="text-align:right; font-weight:600;">${weatherDesc}</td></tr>
        <tr style="border-bottom:1px solid #e2e8f0;"><td style="padding:8px 0; color:#64748b;">Temperature</td><td style="text-align:right; font-weight:600;">${tempC}°C</td></tr>
        <tr><td style="padding:8px 0; color:#64748b;">Wind Speed</td><td style="text-align:right; font-weight:600;">${windKph} km/h</td></tr>
      </table>
    </div>

    <!-- Crypto -->
    <div style="padding: 20px;">
      <h2 style="margin: 0 0 14px; font-size: 16px;">₿ Crypto Prices <span style="font-weight:normal; color:#64748b; font-size:13px;">(USD)</span></h2>
      <table style="width:100%; border-collapse: collapse; font-size: 15px;">
        <tr style="border-bottom:1px solid #f1f5f9;">
          <td style="padding:8px 0; color:#64748b;">Bitcoin</td>
          <td style="text-align:right;"><strong>$${btcPrice}</strong> <span style="font-size:13px; margin-left:8px;">${fmt(btcChange)}</span></td>
        </tr>
        <tr style="border-bottom:1px solid #f1f5f9;">
          <td style="padding:8px 0; color:#64748b;">Ethereum</td>
          <td style="text-align:right;"><strong>$${ethPrice}</strong> <span style="font-size:13px; margin-left:8px;">${fmt(ethChange)}</span></td>
        </tr>
        <tr>
          <td style="padding:8px 0; color:#64748b;">Solana</td>
          <td style="text-align:right;"><strong>$${solPrice}</strong> <span style="font-size:13px; margin-left:8px;">${fmt(solChange)}</span></td>
        </tr>
      </table>
    </div>

  </div>

  <p style="text-align:center; color:#94a3b8; font-size:12px; margin-top:16px;">Generated automatically by n8n</p>

</body>
</html>
`.trim();

return { report, today };
